import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function checkCircuitBreaker(chainName, agentWallet, maxDrawdownUSD = 1000) {
  const balances = await client.BalanceService.getTokenBalancesForWalletAddress(
    chainName, agentWallet
  );
  const totalUSD = (balances.data?.items ?? []).reduce((s, i) => s + (i.quote ?? 0), 0);
  const breached = totalUSD < maxDrawdownUSD;
  return { agentWallet, totalUSD, breached, action: breached ? "PAUSE" : "OK" };
}
